import{_ as e,o as a,c as l,a3 as s}from"./chunks/framework.BTFg6ESq.js";const c=JSON.parse('{"title":"Agent 资产管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/agents/assets.md","filePath":"user-guide/tools/llm-chat/agents/assets.md","lastUpdated":1778244893000}'),r={name:"user-guide/tools/llm-chat/agents/assets.md"};function o(n,t,i,d,g,h){return a(),l("div",null,[...t[0]||(t[0]=[s('<div><h1 id="agent-资产管理" tabindex="-1">Agent 资产管理 <a class="header-anchor" href="#agent-资产管理" aria-label="Permalink to &quot;Agent 资产管理&quot;">​</a></h1><p>Agent 资产（Assets）系统允许用户为每个智能体绑定专属的多媒体资源（图片、音频、视频、文档等）。这些资产不仅可以用于 UI 展示，还可以通过特殊的协议和宏系统注入到提示词中，供大语言模型（LLM）理解和引用。</p><h2 id="一、核心概念-agent-asset-协议" tabindex="-1">一、核心概念：agent-asset:// 协议 <a class="header-anchor" href="#一、核心概念-agent-asset-协议" aria-label="Permalink to &quot;一、核心概念：agent-asset:// 协议&quot;">​</a></h2><p>系统定义了一套专有的 URI 协议，用于在消息内容或提示词模板中引用 Agent 专属资产。</p><h3 id="_1-协议格式" tabindex="-1">1. 协议格式 <a class="header-anchor" href="#_1-协议格式" aria-label="Permalink to &quot;1. 协议格式&quot;">​</a></h3><p>标准的引用格式如下： <code>agent-asset://{group}/{id}.{ext}</code></p><ul><li><strong>group</strong>: 资产所属的分组 ID（默认为 <code>default</code>）。</li><li><strong>id</strong>: 资产的唯一标识符（通常是不带后缀的文件名）。</li><li><strong>ext</strong>: 文件扩展名（可选，用于辅助渲染引擎识别类型）。</li></ul><p><strong>示例：</strong></p><ul><li><code>agent-asset://emojis/happy.png</code>：引用表情包分组下的 happy 图片。</li><li><code>agent-asset://bgm/theme_song.mp3</code>：引用背景音乐分组下的主题曲。</li></ul><h3 id="_2-引用与解析" tabindex="-1">2. 引用与解析 <a class="header-anchor" href="#_2-引用与解析" aria-label="Permalink to &quot;2. 引用与解析&quot;">​</a></h3><ul><li><strong>消息内引用</strong>：在发送给 AI 的消息或 AI 的回复中包含此协议链接时，UI 渲染引擎会自动将其解析为对应的媒体组件（如图片卡片、音频播放器）。</li><li><strong>提示词引用</strong>：在系统提示词中使用该协议，可以告诉 AI 某些资产的存在及其含义，AI 可以根据上下文决定在回复中输出这些链接。</li></ul><h2 id="二、资产分组管理" tabindex="-1">二、资产分组管理 <a class="header-anchor" href="#二、资产分组管理" aria-label="Permalink to &quot;二、资产分组管理&quot;">​</a></h2><p>为了应对大量资产，系统提供了灵活的分组机制。</p><h3 id="_1-分组定义-asset-group" tabindex="-1">1. 分组定义 (Asset Group) <a class="header-anchor" href="#_1-分组定义-asset-group" aria-label="Permalink to &quot;1. 分组定义 (Asset Group)&quot;">​</a></h3><p>每个分组包含以下属性：</p><ul><li><strong>ID</strong>：唯一标识，用于协议路径。</li><li><strong>显示名称</strong>：UI 界面展示的名称。</li><li><strong>图标</strong>：支持使用 Emoji 作为分组图标。</li><li><strong>描述</strong>：描述该分组的用途，有助于 LLM 理解资产背景。</li><li><strong>排序</strong>：控制侧边栏分组的显示顺序。</li></ul><h3 id="_2-批量操作" tabindex="-1">2. 批量操作 <a class="header-anchor" href="#_2-批量操作" aria-label="Permalink to &quot;2. 批量操作&quot;">​</a></h3><p>在资产管理器中，你可以进入<strong>批量模式</strong>：</p><ul><li><strong>批量移动</strong>：将选中的多个资产一键转移到另一个分组。</li><li><strong>批量删除</strong>：物理删除选中的资产文件及其元数据。</li><li><strong>拖拽归类</strong>：直接将资产卡片拖拽到左侧的分组列表上即可完成移动。</li></ul><h2 id="三、资产类型与处理" tabindex="-1">三、资产类型与处理 <a class="header-anchor" href="#三、资产类型与处理" aria-label="Permalink to &quot;三、资产类型与处理&quot;">​</a></h2><p>系统支持多种类型的资产，并根据文件 MIME 类型自动归类：</p><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">常见后缀</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>图片 (Image)</strong></td><td style="text-align:left;">.png, .jpg, .webp, .gif</td><td style="text-align:left;">支持在线预览、缩略图生成。</td></tr><tr><td style="text-align:left;"><strong>音频 (Audio)</strong></td><td style="text-align:left;">.mp3, .wav, .ogg</td><td style="text-align:left;">支持在线播放，可配置封面图（Poster）。</td></tr><tr><td style="text-align:left;"><strong>视频 (Video)</strong></td><td style="text-align:left;">.mp4, .webm</td><td style="text-align:left;">支持内置播放器预览。</td></tr><tr><td style="text-align:left;"><strong>文件 (File)</strong></td><td style="text-align:left;">.pdf, .txt, .docx</td><td style="text-align:left;">通用文件类型，提供下载和路径引用。</td></tr></tbody></table><h3 id="缩略图机制" tabindex="-1">缩略图机制 <a class="header-anchor" href="#缩略图机制" aria-label="Permalink to &quot;缩略图机制&quot;">​</a></h3><p>对于视频和音频资产，系统支持关联一个 <code>thumbnailPath</code>。</p><ul><li><strong>视频</strong>：自动截取首帧作为缩略图。</li><li><strong>音频</strong>：用户可以手动指定一张图片作为该音频在 UI 中的封面。</li></ul><h2 id="四、导入与导出" tabindex="-1">四、导入与导出 <a class="header-anchor" href="#四、导入与导出" aria-label="Permalink to &quot;四、导入与导出&quot;">​</a></h2><p>资产系统支持多种迁移方式，确保数据的流动性。</p><h3 id="_1-物理存储" tabindex="-1">1. 物理存储 <a class="header-anchor" href="#_1-物理存储" aria-label="Permalink to &quot;1. 物理存储&quot;">​</a></h3><p>所有资产物理存储在应用数据目录下的 <code>llm-chat/agents/{agentId}/assets/</code> 目录中。你可以通过界面上的“打开目录”按钮直接访问原始文件。</p><h3 id="_2-sillytavern-兼容导入" tabindex="-1">2. SillyTavern 兼容导入 <a class="header-anchor" href="#_2-sillytavern-兼容导入" aria-label="Permalink to &quot;2. SillyTavern 兼容导入&quot;">​</a></h3><p>系统内置了对 SillyTavern 角色卡及预设的兼容支持：</p><ul><li>支持解析 ST 的 <code>{{item}}</code> 格式并转换为本系统的资产定义。</li><li>在导入角色卡时，会自动将关联的表情包、背景图等资源存入对应的资产分组。</li></ul><h3 id="_3-json-导出" tabindex="-1">3. JSON 导出 <a class="header-anchor" href="#_3-json-导出" aria-label="Permalink to &quot;3. JSON 导出&quot;">​</a></h3><p>你可以将整个 Agent 的配置（包含资产元数据定义）导出为 JSON 文件。注意：JSON 导出仅包含路径和配置信息，不包含物理文件本身。若要迁移整个 Agent，建议直接备份物理目录。</p><h2 id="五、与宏系统联动" tabindex="-1">五、与宏系统联动 <a class="header-anchor" href="#五、与宏系统联动" aria-label="Permalink to &quot;五、与宏系统联动&quot;">​</a></h2><p>资产系统深度集成了<a href="./../macro-system/">宏引擎</a>，支持动态注入。</p><h3 id="_1-assets-宏" tabindex="-1">1. {{assets}} 宏 <a class="header-anchor" href="#_1-assets-宏" aria-label="Permalink to &quot;1. {{assets}} 宏&quot;">​</a></h3><ul><li><strong>{{assets}}</strong>：注入当前 Agent 所有已启用资产的列表及描述。</li><li><strong>{{assets::groupId}}</strong>：仅注入指定分组下的资产信息。这对于告诉 AI 它可以调用哪些表情包或背景音乐非常有用。</li></ul><h3 id="_2-注入策略" tabindex="-1">2. 注入策略 <a class="header-anchor" href="#_2-注入策略" aria-label="Permalink to &quot;2. 注入策略&quot;">​</a></h3><p>资产引用的注入遵循 Agent 的<strong>消息注入策略</strong>。你可以将包含资产引用的消息配置为：</p><ul><li><strong>深度注入 (Depth)</strong>：在对话历史的特定深度插入资产说明。</li><li><strong>锚点注入 (Anchor)</strong>：在系统提示词或角色定义之后紧跟资产列表。</li></ul><hr><p><strong>相关阅读：</strong></p><ul><li><a href="./editor-guide">智能体编辑器</a></li><li><a href="./../macro-system/macro-reference">宏系统参考</a></li><li><a href="./st-compatibility">SillyTavern 导入指南</a></li></ul></div>',1)])])}const p=e(r,[["render",o]]);export{c as __pageData,p as default};
